1	// The scheduler entrypoint's orchestration core (per-project-scheduling DESIGN
2	// §3). The vendored hourly Action runs this: decide due slots from the run
3	// ledger, discover active tasks, collect only the signals the due tasks declare,
4	// run each precondition, and either dispatch agent work as a `ready-for-agent`
5	// issue or (for `agent_model: none`) run the worker inline.
6	//
7	// This module is the DECISION core, kept injectable so it tests with fakes: the
8	// GitHub I/O (the Actions run-ledger read for `lastSuccess`, the signal
9	// collectors, the issue search/create) is supplied by the thin CLI shell around
10	// `planRun`. The "should this run" verdict is always code here — never the
11	// shell's judgment (the same split the fleet planner uses).
12	
13	import { join } from 'node:path';
14	import { pathToFileURL } from 'node:url';
15	import { dueSlots } from './slots.mjs';
16	import { planDispatch, dispatchTitle, dispatchBody, DISPATCH_PREFIX, READY_LABEL, SCHEDULER_LABELS } from './dispatch.mjs';
17	import { isAgentless } from './model-map.mjs';
18	
19	// The due tasks, each paired with the slot it runs under. Union the discovered
20	// tasks' frequencies, ask slots which are due (run-ledger math), then map due
21	// frequencies back to their tasks. A task whose frequency isn't due drops out.
22	export function computeDueTaskSlots(tasks, schedule, now, lastSuccess) {
23	  const frequencies = [...new Set(tasks.map((t) => t.decl.frequency))];
24	  const due = new Map(dueSlots(frequencies, schedule, now, lastSuccess).map((d) => [d.frequency, d]));
25	  const out = [];
26	  for (const task of tasks) {
27	    const slot = due.get(task.decl.frequency);
28	    if (slot) out.push({ task, slotId: slot.slotId, slotTime: slot.slotTime });
29	  }
30	  return out;
31	}
32	
33	// The union of signal names the due tasks declare — the scheduler collects only
34	// these, so a non-daily slot never pays for daily tasks' signals (DESIGN §3.3).
35	export function signalsUnion(dueTaskSlots) {
36	  const names = new Set();
37	  for (const { task } of dueTaskSlots) for (const name of task.decl.precondition_signals) names.add(name);
38	  return [...names];
39	}
40	
41	// The signal-collection lookback: the widest due task's period plus 1h slack
42	// (DESIGN §3.3). Stateless fixed lookback — overlap is absorbed by dedupe.
43	const FREQUENCY_MS = {
44	  hourly: 3600e3, 'daily-2h': 86400e3, 'daily-1h': 86400e3, daily: 86400e3,
45	  'daily+1h': 86400e3, weekly: 7 * 86400e3, monthly: 31 * 86400e3,
46	};
47	export function windowStart(dueTaskSlots, now) {
48	  const widest = Math.max(0, ...dueTaskSlots.map(({ task }) => FREQUENCY_MS[task.decl.frequency] ?? 86400e3));
49	  return new Date(new Date(now).getTime() - widest - 3600e3).toISOString();
50	}
51	
52	// Run one task's precondition in isolation (DESIGN §3.4). A throwing
53	// precondition converges to a skip with the error recorded — it never sinks the
54	// rest of the run; the CLI escalates a thrown precondition to a workflow-failure
55	// issue separately.
56	export function runPrecondition(task, signals, packConfig) {
57	  try {
58	    const v = task.decl.precondition(signals, packConfig) ?? {};
59	    return {
60	      run: v.run === true,
61	      reason: v.reason ?? '',
62	      context: Array.isArray(v.context) ? v.context : [],
63	    };
64	  } catch (e) {
65	    return { run: false, reason: `precondition threw: ${e.message}`, context: [], error: e.message };
66	  }
67	}
68	
69	// A human-readable job-summary line per evaluated task — the observability the
70	// old plan.json gave (DESIGN §3.6).
71	export function renderSummary(evaluations) {
72	  return evaluations.map((e) => {
73	    const verb = !e.run ? 'skip' : e.inline ? 'run-inline' : e.dispatch?.action ?? 'run';
74	    return `- ${e.pack}/${e.task} [${e.slotId}] ${verb} — ${e.reason || e.dispatch?.reason || ''}`.trimEnd();
75	  }).join('\n');
76	}
77	
78	// Orchestrate one scheduler run into a set of decisions — the reusable core the
79	// CLI wraps with real GitHub I/O. Injected seams:
80	//   collectSignals(names) -> signals object (the declared union, collected once)
81	//   packConfigFor(packId) -> that pack's entry config from .claudinite-checks.json
82	//   existingIssuesFor(pack, task) -> the task family's issues [{number,title,state}]
83	// Returns `{ evaluations }`: one record per due task with its precondition
84	// verdict and, when it runs, either an inline marker (agent_model: none) or a
85	// dispatch decision (planDispatch).
86	export async function planRun({
87	  tasks, schedule, now, lastSuccess,
88	  collectSignals, packConfigFor = () => ({}), existingIssuesFor = async () => [],
89	}) {
90	  const dueList = computeDueTaskSlots(tasks, schedule, now, lastSuccess);
91	  const signals = await collectSignals(signalsUnion(dueList));
92	
93	  const evaluations = [];
94	  for (const { task, slotId } of dueList) {
95	    const pre = runPrecondition(task, signals, packConfigFor(task.pack));
96	    const rec = {
97	      pack: task.pack, task: task.id, slotId,
98	      model: task.decl.agent_model, outcome: task.decl.expected_outcome,
99	      run: pre.run, reason: pre.reason, context: pre.context,
100	    };
101	    if (pre.error) rec.error = pre.error;
102	    if (pre.run) {
103	      if (isAgentless(task.decl.agent_model)) {
104	        // agent_model: none — the worker is code the scheduler runs inline; no issue.
105	        rec.inline = true;
106	      } else {
107	        const existing = await existingIssuesFor(task.pack, task.id);
108	        rec.dispatch = planDispatch({ existing, pack: task.pack, task: task.id, slotId });
109	      }
110	    }
111	    evaluations.push(rec);
112	  }
113	  return { evaluations };
114	}
115	
116	// --- CLI: the thin I/O shell the vendored workflow invokes -------------------
117	// Wires the run-ledger read, signal collectors, and issue I/O around planRun,
118	// then acts on each decision (file a labeled dispatch issue, or run an inline
119	// worker) and prints the job summary. All GitHub access here is the Action's
120	// GITHUB_TOKEN — the one sanctioned non-MCP surface (DESIGN §10).
121	
122	// The task family's issues (state=all) via the search API, filtered to exact
123	// prefix — the input planDispatch's exactly-once / at-most-one-open guards read.
124	async function existingIssuesViaSearch(gh, repo, pack, task) {
125	  const q = encodeURIComponent(`repo:${repo} in:title "${DISPATCH_PREFIX} ${pack}/${task}"`);
126	  const { status, json } = await gh(`/search/issues?q=${q}&per_page=100`);
127	  if (status !== 200 || !Array.isArray(json?.items)) return [];
128	  const prefix = `${DISPATCH_PREFIX} ${pack}/${task} `;
129	  return json.items
130	    .filter((i) => `${(i.title ?? '').trim()} `.startsWith(prefix))
131	    .map((i) => ({ number: i.number, title: i.title, state: i.state }));
132	}
133	
134	// Ensure the dispatch labels exist before any is applied — GitHub 422s when you
135	// apply an unknown label (it never creates one on demand), so the scheduler, as the
136	// thing that assigns them, guarantees them here. Idempotent (201 created / 422 already
137	// exists are both success) and self-healing (a deleted label reappears next run), which
138	// is why no separate one-off label-creation step is needed. Exported for the run tests.
139	export async function ensureLabels(gh, repo, labels) {
140	  for (const { name, color, description } of labels) {
141	    const res = await gh(`/repos/${repo}/labels`, { method: 'POST', body: { name, color, description } });
142	    if (res.status !== 201 && res.status !== 422) {
143	      console.log(`! could not ensure label "${name}": ${res.status}`);
144	    }
145	  }
146	}
147	
148	async function main() {
149	  const { makeGh, lastSuccessTime, actionRepoContext } = await import('./signals/gh.mjs');
150	  const { collectSignals } = await import('./signals/index.mjs');
151	  const { discoverTasks } = await import('./discover.mjs');
152	  const { loadConfig } = await import('../checks/helpers/repo-context.mjs');
153	
154	  const root = process.cwd();
155	  const { repo, defaultBranch } = actionRepoContext();
156	  if (!repo) { console.error('GITHUB_REPOSITORY not set — not in an Actions context'); process.exit(1); }
157	  const gh = makeGh();
158	  const config = loadConfig(root);
159	
160	  const { tasks, errors } = await discoverTasks(root, config);
161	  for (const e of errors) console.log(`! ${e.what}`);
162	
163	  const now = new Date();
164	  const lastSuccess = await lastSuccessTime(gh, repo);
165	  const schedule = config.taskScheduler;
166	
167	  const due = computeDueTaskSlots(tasks, schedule, now, lastSuccess);
168	  const sinceIso = windowStart(due, now);
169	  const ctx = {
170	    repo, defaultBranch, now: now.toISOString(), sinceIso, config,
171	    activePacks: config.packs,
172	  };
173	  const packConfigFor = (packId) => config.packConfig?.[packId] ?? {};
174	
175	  const { evaluations } = await planRun({
176	    tasks, schedule, now, lastSuccess,
177	    collectSignals: (names) => collectSignals(gh, ctx, names),
178	    packConfigFor,
179	    existingIssuesFor: (pack, task) => existingIssuesViaSearch(gh, repo, pack, task),
180	  });
181	
182	  // Guarantee the dispatch labels exist before we file any labeled issue (only when
183	  // we're actually about to dispatch — an idle run pays nothing).
184	  if (evaluations.some((r) => r.run && !r.inline && r.dispatch?.action === 'create')) {
185	    await ensureLabels(gh, repo, SCHEDULER_LABELS);
186	  }
187	
188	  for (const rec of evaluations) {
189	    if (!rec.run) continue;
190	    const taskObj = tasks.find((t) => t.pack === rec.pack && t.id === rec.task);
191	    if (rec.inline) {
192	      // agent_model: none — run the worker module inline (it may itself dispatch a workflow).
193	      try {
194	        const workerUrl = pathToFileURL(join(taskObj.taskDir, taskObj.decl.agent_instructions)).href;
195	        const worker = (await import(workerUrl)).default;
196	        if (typeof worker === 'function') await worker({ gh, repo, ctx, slotId: rec.slotId });
197	      } catch (e) { console.log(`! inline worker ${rec.pack}/${rec.task} failed: ${e.message}`); }
198	      continue;
199	    }
200	    if (rec.dispatch?.action === 'create') {
201	      const title = dispatchTitle({ pack: rec.pack, task: rec.task, slotId: rec.slotId });
202	      const body = dispatchBody({ taskPath: taskObj.taskPath, pack: rec.pack, task: rec.task, slotId: rec.slotId, context: rec.context });
203	      const res = await gh(`/repos/${repo}/issues`, { method: 'POST', body: { title, body, labels: [READY_LABEL] } });
204	      if (res.status >= 300) console.log(`! failed to file dispatch issue for ${rec.pack}/${rec.task}: ${res.status}`);
205	    }
206	  }
207	
208	  console.log('## Claudinite scheduler\n');
209	  console.log(renderSummary(evaluations) || '- no tasks due');
210	}
211	
212	// Run only when invoked directly (the workflow's `node run.mjs`), never on import.
213	if (process.argv[1] && import.meta.url === pathToFileURL(process.argv[1]).href) {
214	  main().catch((e) => { console.error(e); process.exit(1); });
215	}
