1	// grow_with_claudinite task: conversation-extract — the conversation-side sibling
2	// of growth-extract (per-project-scheduling DESIGN §6). Mines the repo's captured
3	// conversation logs (the orphan `conversation-logs` branch) for durable lessons,
4	// posts the dialogue behind each extracted rule on the issue it was worked under,
5	// and prunes logs past the entry's retention. Worker: task.md.
6	//
7	// Self-contained (imports nothing): the whole contract is this default export.
8	
9	export default {
10	  id: 'conversation-extract',
11	  frequency: 'daily-1h',           // the 03:00 slot, alongside growth-extract (DESIGN §2)
12	  precondition_signals: ['commits', 'conversationLogs'],
13	  agent_model: 'opus',                   // deciding what clears the lesson bar is the heaviest judgment, and its PR auto-merges without a human gate
14	  expected_outcome: 'merged-pr',            // lessons ride an auto-merging PR; the retention prune is a push to the non-default logs branch (outside the taxonomy)
15	  agent_instructions: 'task.md',
16	
17	  // Two independent reasons to run, so the age-based prune fires on quiet repos
18	  // too (the old weekly-full crutch retires — a log ages out on wall time, not on
19	  // the repo changing, DESIGN §6):
20	  //   (a) a substantive merge — a fresh capture now sits on the logs branch;
21	  //   (b) the logs branch exists AND retention is configured — there may be aged
22	  //       logs to give a final hindsight pass and prune, regardless of activity.
23	  precondition(signals) {
24	    const substantive = signals.commits?.substantiveChange === true;
25	    const logs = signals.conversationLogs ?? {};
26	    const canPrune = logs.present === true && typeof logs.retentionDays === 'number';
27	
28	    if (substantive) {
29	      return { run: true, reason: 'substantive merge — extract any freshly captured conversation logs (+ retention prune)' };
30	    }
31	    if (canPrune) {
32	      return { run: true, reason: `logs branch present, retention ${logs.retentionDays}d — run the age-based retention prune` };
33	    }
34	    return { run: false, reason: logs.present ? 'no substantive merge and retention unset — nothing to prune' : 'no fresh captures and no logs branch' };
35	  },
36	};
37

1	// grow_with_claudinite task: growth-extract — the growth lifecycle's CAPTURE
2	// stage (per-project-scheduling DESIGN §6). Reviews the repo's recent activity and
3	// folds any durable, reusable lesson into the repo's own local packs, landing
4	// through a PR that auto-merges once the repo's checks pass. Worker: task.md.
5	//
6	// Self-contained (imports nothing): the whole contract is this default export.
7	
8	export default {
9	  id: 'growth-extract',
10	  frequency: 'daily-1h',           // the 03:00 slot — lessons captured from an already-converged mount (DESIGN §2)
11	  precondition_signals: ['commits', 'prs', 'issues'],
12	  agent_model: 'opus',                   // generalizing/curating lessons is the heaviest judgment, and auto-merge means no human reviews the PR
13	  expected_outcome: 'merged-pr',            // additive edits to the repo's own local packs; arms auto-merge after CI
14	  agent_instructions: 'task.md',
15	
16	  // Fire on a SUBSTANTIVE default-branch change (not any change): a bot bump /
17	  // [skip ci] / nightly-baselining commit advancing main is not a lesson to
18	  // extract — `commits.substantiveChange` already applies that classification.
19	  // Pass the substantive shas + touched PR/issue numbers as binding scope so the
20	  // worker reads exactly the window that triggered it.
21	  precondition(signals) {
22	    const commits = signals.commits ?? {};
23	    if (!commits.substantiveChange) {
24	      return { run: false, reason: 'no substantive default-branch change in the window' };
25	    }
26	    const shas = (commits.list ?? []).filter((c) => c.substantive).map((c) => c.sha.slice(0, 7));
27	    const prs = signals.prs?.touched ?? [];
28	    const issues = signals.issues?.touched ?? [];
29	    const context = [`Scope: the ${shas.length} substantive commit(s) in the window — ${shas.join(', ')}.`];
30	    if (prs.length) context.push(`PRs touched in the window: ${prs.map((n) => `#${n}`).join(', ')}.`);
31	    if (issues.length) context.push(`Issues touched in the window: ${issues.map((n) => `#${n}`).join(', ')}.`);
32	    return { run: true, reason: `${shas.length} substantive commit(s) in the window`, context };
33	  },
34	};
35

1	// grow_with_claudinite task: growth-dedup — the growth lifecycle's PRUNING stage
2	// (per-project-scheduling DESIGN §6). Prunes local-pack items the canon now
3	// covers, keeping items the canon states too generally; opens a PR against the
4	// default branch for the owner to approve. Worker: task.md.
5	//
6	// The old fleet's `relevantCanonChanged` becomes the `sharedMount` signal — a
7	// declared pack's vendored files moving is the local echo of "the canon this repo
8	// mounts changed" — and the weekly re-check crutch retires: a quiet repo with no
9	// local packs skips.
10	//
11	// Self-contained (imports nothing): the whole contract is this default export.
12	
13	export default {
14	  id: 'growth-dedup',
15	  frequency: 'daily+1h',           // the 05:00 slot — prunes against the merged/mounted canon, after promote (DESIGN §2)
16	  precondition_signals: ['localPacks', 'sharedMount', 'commits'],
17	  agent_model: 'opus',                   // proving the canon genuinely covers a local item — and telling coverage from "stated too generally" — is a judgment call
18	  expected_outcome: 'open-pr',              // a wrongful prune deletes a real local lesson, so this keeps a HUMAN approval gate (never auto-merge)
19	  agent_instructions: 'task.md',
20	
21	  // Gate: the repo must actually track local packs (no local packs → nothing to
22	  // prune, self-skip). Given local packs, run when the mounted canon this repo
23	  // CARES about moved — a declared pack's vendored files changed (`sharedMount`),
24	  // which can newly cover a local item — or the repo's own local packs changed in
25	  // the window (a fresh local item to re-check against the canon). A quiet repo
26	  // with local packs but no relevant movement skips.
27	  precondition(signals) {
28	    const local = signals.localPacks ?? {};
29	    // `present` is null when the scheduler couldn't determine it; treat only an
30	    // explicit false as "definitely no local packs to prune".
31	    if (local.present === false) {
32	      return { run: false, reason: 'no local packs — nothing to prune' };
33	    }
34	    const changedPacks = signals.sharedMount?.changedPacks ?? [];
35	    const canonMoved = changedPacks.length > 0;
36	    const localChanged = local.changedInWindow === true;
37	
38	    if (canonMoved) {
39	      return { run: true, reason: `declared pack(s) changed in the mounted canon: ${changedPacks.join(', ')} — local items may now be covered`, context: [`Re-check local items against these newly-changed canon packs: ${changedPacks.join(', ')}.`] };
40	    }
41	    if (localChanged) {
42	      return { run: true, reason: 'local packs changed in the window — re-check the fresh items against the mounted canon' };
43	    }
44	    return { run: false, reason: 'local packs present but no relevant canon or local movement in the window' };
45	  },
46	};
47

1	// chrome-extension-release task: store-release — the pack-contributed release
2	// trigger (per-project-scheduling DESIGN §6). STRUCTURAL Stage 2: `model: 'none'`
3	// means the whole decision is code and there is NO agent and NO dispatch issue —
4	// the scheduler runs the inline `worker.mjs` directly. This task ABSORBS the
5	// release workflow's own independent 00:30 cron: the workflow becomes push +
6	// workflow_dispatch only, and this task is the one place that fires its daily
7	// leg, so the scheduler stays the repo's only cron (DESIGN §3, decision §11.6).
8	//
9	// Self-contained (imports nothing): the whole contract is this default export.
10	
11	const norm = (v) => String(v ?? '').replace(/^v/, '').trim(); // compare tags/versions modulo a leading 'v'
12	
13	export default {
14	  id: 'store-release',
15	  frequency: 'daily',              // the 04:00 slot (DESIGN §2) — replaces the workflow's own 00:30 cron
16	  precondition_signals: ['release', 'commits'],
17	  agent_model: 'none',                   // pure code — the worker is an inline .mjs, not an agent (DESIGN §1)
18	  expected_outcome: 'none',                 // it only TRIGGERS the gated publish workflow; publishing stays behind that workflow's own guards
19	  agent_instructions: 'worker.mjs',            // model:none → the worker is the inline module named here, run by the scheduler
20	
21	  // Detect a deployable change since the last release, entirely in code:
22	  //   (a) the manifest version has advanced past the latest published release
23	  //       (an unreleased bump — the same signal the old run_daily gate used), OR
24	  //   (b) a substantive default-branch commit landed in the window (a real ship).
25	  // Ship-path precision (the daily job's `ship_paths` filter) is NOT re-derived
26	  // here — .github/release.config isn't in a precondition's scope — because the
27	  // dispatched daily workflow does the authoritative shipped-file diff vs the
28	  // latest release tag and no-ops when nothing shippable moved. So the
29	  // precondition is the cheap pre-filter; the workflow is the exact gate.
30	  precondition(signals) {
31	    const rel = signals.release ?? {};
32	    const shipped = norm(rel.manifestVersion);
33	    const released = norm(rel.latestTag);
34	    const manifestAhead = shipped !== '' && shipped !== released;
35	    const substantive = signals.commits?.substantiveChange === true;
36	
37	    if (manifestAhead) {
38	      return { run: true, reason: released ? `manifest ${shipped} is ahead of released ${released}` : `manifest ${shipped}, no release yet` };
39	    }
40	    if (substantive) {
41	      return { run: true, reason: 'substantive default-branch change in the window — let the daily release workflow diff shipped files' };
42	    }
43	    return { run: false, reason: 'manifest matches the latest release and no substantive change in the window' };
44	  },
45	};
46

1	import { readdirSync, readFileSync, existsSync } from 'node:fs';
2	import { join, dirname } from 'node:path';
3	import { fileURLToPath } from 'node:url';
4	import { loadPacks, resolveDeclaredPacks, packEntryId, SHARED_SUBDIR } from '../engine/pack_loader/pack-registry.mjs';
5	import { relativeImports, resolveRelative, ENGINE_DIR_ROOTS } from '../engine/checks/helpers/module-imports.mjs';
6	
7	// The vendor-set computation for the vendored mount (DESIGN.md): given a repo's
8	// pack declaration, the minimal corpus file set that repo persists under
9	// SHARED_SUBDIR — canon-relative paths, mirroring exactly what a future
10	// submodule mounted at that same root would place there. Always computed
11	// against the canon tree THIS module ships in — the nightly runs it from the
12	// home checkout, an on-demand refresh from the tree it just fetched — so the
13	// set and the content can never come from different snapshots.
14	const canonRoot = dirname(dirname(fileURLToPath(import.meta.url))); // <canon>/vendoring/ — canon-internal, never vendored (#385)
15	
16	// Re-exported for the writers (the nightly update pass, an on-demand refresh):
17	// the consumer-side root the set materializes under.
18	export { SHARED_SUBDIR };
19	
20	// The engine is discovered structurally, never listed file-by-file: the engine
21	// root vendors wholesale (a new engine file ships with no edit here). The list
22	// lives in the engine lib (engine/checks/helpers/module-imports.mjs) — the same
23	// surface the pack-independence barrier confines pack imports to, so "what a
24	// pack may import" and "what every consumer carries" can never drift apart —
25	// re-exported here as the vendor-set contract (DESIGN.md). engine/ carries no
26	// tests (they live in engine-tests/, mirroring its structure — #385), so the
27	// engine walk is a plain copy minus *.md — engine docs are canon-maintainer
28	// reference, read upstream when needed, while a pack's .md files are the
29	// payload and ride its directory below (pack tests are still filtered here).
30	export { ENGINE_DIR_ROOTS };
31	
32	const isTest = (name) => name.endsWith('.test.mjs');
33	
34	function walk(relDir, files, errors, { engine = false } = {}) {
35	  let entries;
36	  try {
37	    entries = readdirSync(join(canonRoot, relDir), { withFileTypes: true });
38	  } catch (e) {
39	    errors.push({
40	      what: `${relDir} is not a readable directory in the canon tree: ${e.message}`,
41	      fix: `restore ${relDir}, or fix what names it (an engine root, a pack.mjs skills list)`,
42	    });
43	    return;
44	  }
45	  for (const entry of entries.sort((a, b) => a.name.localeCompare(b.name))) {
46	    if (entry.isDirectory()) {
47	      if (engine && entry.name === 'test') continue;
48	      walk(`${relDir}/${entry.name}`, files, errors, { engine });
49	    } else if (!isTest(entry.name) && !(engine && entry.name.endsWith('.md'))) {
50	      files.add(`${relDir}/${entry.name}`);
51	    }
52	  }
53	}
54	
55	// declaredEntries: the raw `packs` array from .claudinite-checks.json (id
56	// strings and/or entry objects). Returns { files, errors }:
57	// sorted canon-relative paths, and { what, fix } diagnostics. Ids naming no
58	// canon pack (a consumer's local packs, or a typo the runner's settings
59	// validation already flags) are skipped without error; per-user preferences
60	// are deliberately absent — they are never vendored (DESIGN.md). A pack's
61	// bundled skills (<pack>/skills/) ride its directory walk — there is no
62	// separate skills collection to union (#385).
63	export async function computeVendorSet(declaredEntries) {
64	  const files = new Set();
65	  const errors = [];
66	
67	  for (const root of ENGINE_DIR_ROOTS) walk(root, files, errors, { engine: true });
68	
69	  const packs = await loadPacks();
70	  const byId = new Map(packs.map((p) => [p.id, p]));
71	  const ids = [];
72	  for (const entry of resolveDeclaredPacks(declaredEntries ?? [], packs)) {
73	    const id = packEntryId(entry);
74	    if (id !== undefined && byId.has(id) && !ids.includes(id)) ids.push(id);
75	  }
76	  for (const id of ids) walk(`packs/${id}`, files, errors);
77	
78	  // Coherence guard: the set must be import-closed — every relative import in
79	  // every .mjs it carries resolves to a file it also carries. Structural
80	  // discovery plus the requires closure make that true by construction while
81	  // the corpus honors pack-independence (a pack imports only its own files and
82	  // the engine surface, both always in the set); a violation is canon-side
83	  // breakage, reported here so convergence aborts BEFORE any write (the
84	  // transactional contract) instead of the flipped member crashing on a
85	  // missing module — the failure the gated flip's pilot abort surfaced.
86	  const inSet = new Set(files);
87	  for (const file of inSet) {
88	    if (!file.endsWith('.mjs')) continue;
89	    let src;
90	    try { src = readFileSync(join(canonRoot, file), 'utf8'); } catch { continue; }
91	    for (const { spec } of relativeImports(src)) {
92	      const resolved = resolveRelative(file, spec, (p) => existsSync(join(canonRoot, p)));
93	      if (!resolved) {
94	        errors.push({
95	          what: `${file} imports "${spec}", which resolves to no file in the canon tree`,
96	          fix: 'fix the import specifier, or restore the file it names',
97	        });
98	      } else if (!inSet.has(resolved)) {
99	        errors.push({
100	          what: `${file} imports "${spec}" → ${resolved}, which the vendor set does not carry — a pack imports only its own files and the engine surface (pack-independence)`,
101	          fix: 'fix the import to honor pack-independence (declare the dependency and contribute configuration, or move the helper into checks/lib)',
102	        });
103	      }
104	    }
105	  }
106	
107	  return { files: [...files].sort(), errors };
108	}
109

