1	// grow_with_claudinite task: growth-extract — the growth lifecycle's CAPTURE
2	// stage (per-project-scheduling DESIGN §6). Reviews the repo's recent activity and
3	// folds any durable, reusable lesson into the repo's own local packs, landing
4	// through a PR that auto-merges once the repo's checks pass. Worker: task.md.
5	//
6	// Self-contained (imports nothing): the whole contract is this default export.
7	
8	export default {
9	  id: 'growth-extract',
10	  frequency: 'daily-1h',           // the 03:00 slot — lessons captured from an already-converged mount (DESIGN §2)
11	  precondition_signals: ['commits', 'prs', 'issues'],
12	  agent_model: 'opus',                   // generalizing/curating lessons is the heaviest judgment, and auto-merge means no human reviews the PR
13	  expected_outcome: 'merged-pr',            // additive edits to the repo's own local packs; arms auto-merge after CI
14	  agent_instructions: 'task.md',
15	
16	  // Fire on a SUBSTANTIVE default-branch change (not any change): a bot bump /
17	  // [skip ci] / nightly-baselining commit advancing main is not a lesson to
18	  // extract — `commits.substantiveChange` already applies that classification.
19	  // Pass the substantive shas + touched PR/issue numbers as binding scope so the
20	  // worker reads exactly the window that triggered it.
21	  precondition(signals) {
22	    const commits = signals.commits ?? {};
23	    if (!commits.substantiveChange) {
24	      return { run: false, reason: 'no substantive default-branch change in the window' };
25	    }
26	    const shas = (commits.list ?? []).filter((c) => c.substantive).map((c) => c.sha.slice(0, 7));
27	    const prs = signals.prs?.touched ?? [];
