// basics task: baselining — the per-repo SELF-REFRESH (per-project-scheduling
// DESIGN §6, decision §11.7). Under the old fleet planner this was one leg of a
// central pass over every member; here every repo baselines ITSELF from its own
// scheduler, converging its own `.claudinite/shared/` mount to the current canon
// head, applying the migration notes that landed since its stamp, and advancing
// the stamp — one transactional commit on the `claudinite/maintenance` PR
// (worker: task.md). No cross-repo reach: the read-only canon checkout the
// worker vendors from already rides in the executor session's sources (DESIGN §5).
//
// Self-contained (imports nothing) so the scheduler, executor, and a human all
// load it standalone — the whole contract lives in this default export.

export default {
  id: 'baselining',
  frequency: 'daily-2h',           // the 02:00 slot — a repo's mount is converged before anything reads it (DESIGN §2)
  precondition_signals: ['stamp', 'sharedMount'],
  agent_model: 'sonnet',                 // the bootstrap/alignment merges into settings.json without clobbering — judgment
  expected_outcome: 'merged-pr',            // lands on the maintenance PR; arms auto-merge where member config allows
  agent_instructions: 'task.md',

  // Run when this repo's vendored mount is behind the canon, or a declared pack's
  // vendored files moved. PURE over the collected signals — no probes here; the
  // worker does the converge/apply/stamp work.
  precondition(signals) {
    const stamp = signals.stamp ?? {};
    const changed = signals.sharedMount?.changedPacks ?? [];

    // No stamp → no vendored mount to refresh (the canon's own repo, or a
    // pre-adoption repo): baselining self-skips, exactly as the old fleet pass
    // skipped home. `ref` null means the same — nothing to converge against.
    if (!stamp.ref && stamp.ageDays === null) {
      return { run: false, reason: 'no vendored mount (no stamp) — nothing to self-refresh' };
    }

    // Primary trigger: the stamp is behind the canon head. `canonHead` is only
    // populated when the Action could read the canon; when it is null we cannot
    // diff, so fall back to stamp AGE — a mount that hasn't refreshed in over a
    // day is due regardless (DESIGN §6, §3.3: "stamp-age fallback when the canon
    // isn't readable from the Action").
    const behindCanon = stamp.canonHead != null && stamp.canonHead !== stamp.ref;
    const staleByAge = stamp.canonHead == null && typeof stamp.ageDays === 'number' && stamp.ageDays > 1;

    // A declared pack's vendored files changed in the window (a member-side edit
    // to the read-only mount, or an already-landed refresh commit) — converge it
    // back to the canon snapshot so drift never accumulates.
    const mountMoved = changed.length > 0;

    if (behindCanon) {
      return { run: true, reason: `mount at ${String(stamp.ref).slice(0, 7)} is behind canon head ${String(stamp.canonHead).slice(0, 7)}`, context: [`Converge \`.claudinite/shared/\` to canon head ${stamp.canonHead} and apply any migration notes dated on/after the stamp (${stamp.updated}).`] };
    }
    if (staleByAge) {
      return { run: true, reason: `canon head unreadable — stamp is ${stamp.ageDays.toFixed(1)}d old (age fallback)`, context: [`Canon head was not readable from the scheduler; refresh from the canon checkout in session and apply notes dated on/after the stamp (${stamp.updated}).`] };
    }
    if (mountMoved) {
      return { run: true, reason: `vendored files changed for declared pack(s): ${changed.join(', ')}`, context: [`Re-converge these packs' vendored files to the canon snapshot: ${changed.join(', ')}.`] };
    }
    return { run: false, reason: 'mount is at canon head and no vendored files moved' };
  },
};

// grow_with_claudinite task: growth-extract — the growth lifecycle's CAPTURE
// stage (per-project-scheduling DESIGN §6). Reviews the repo's recent activity and
// folds any durable, reusable lesson into the repo's own local packs, landing
// through a PR that auto-merges once the repo's checks pass. Worker: task.md.
//
// Self-contained (imports nothing): the whole contract is this default export.

export default {
  id: 'growth-extract',
  frequency: 'daily-1h',           // the 03:00 slot — lessons captured from an already-converged mount (DESIGN §2)
  precondition_signals: ['commits', 'prs', 'issues'],
  agent_model: 'opus',                   // generalizing/curating lessons is the heaviest judgment, and auto-merge means no human reviews the PR
  expected_outcome: 'merged-pr',            // additive edits to the repo's own local packs; arms auto-merge after CI
  agent_instructions: 'task.md',

  // Fire on a SUBSTANTIVE default-branch change (not any change): a bot bump /
  // [skip ci] / nightly-baselining commit advancing main is not a lesson to
  // extract — `commits.substantiveChange` already applies that classification.
  // Pass the substantive shas + touched PR/issue numbers as binding scope so the
  // worker reads exactly the window that triggered it.
  precondition(signals) {
    const commits = signals.commits ?? {};
    if (!commits.substantiveChange) {
      return { run: false, reason: 'no substantive default-branch change in the window' };
    }
    const shas = (commits.list ?? []).filter((c) => c.substantive).map((c) => c.sha.slice(0, 7));
    const prs = signals.prs?.touched ?? [];
    const issues = signals.issues?.touched ?? [];
    const context = [`Scope: the ${shas.length} substantive commit(s) in the window — ${shas.join(', ')}.`];
    if (prs.length) context.push(`PRs touched in the window: ${prs.map((n) => `#${n}`).join(', ')}.`);
    if (issues.length) context.push(`Issues touched in the window: ${issues.map((n) => `#${n}`).join(', ')}.`);
    return { run: true, reason: `${shas.length} substantive commit(s) in the window`, context };
  },
};

// grow_with_claudinite task: conversation-extract — the conversation-side sibling
// of growth-extract (per-project-scheduling DESIGN §6). Mines the repo's captured
// conversation logs (the orphan `conversation-logs` branch) for durable lessons,
// posts the dialogue behind each extracted rule on the issue it was worked under,
// and prunes logs past the entry's retention. Worker: task.md.
//
// Self-contained (imports nothing): the whole contract is this default export.

export default {
  id: 'conversation-extract',
  frequency: 'daily-1h',           // the 03:00 slot, alongside growth-extract (DESIGN §2)
  precondition_signals: ['commits', 'conversationLogs'],
  agent_model: 'opus',                   // deciding what clears the lesson bar is the heaviest judgment, and its PR auto-merges without a human gate
  expected_outcome: 'merged-pr',            // lessons ride an auto-merging PR; the retention prune is a push to the non-default logs branch (outside the taxonomy)
  agent_instructions: 'task.md',

  // Two independent reasons to run, so the age-based prune fires on quiet repos
  // too (the old weekly-full crutch retires — a log ages out on wall time, not on
  // the repo changing, DESIGN §6):
  //   (a) a substantive merge — a fresh capture now sits on the logs branch;
  //   (b) the logs branch exists AND retention is configured — there may be aged
  //       logs to give a final hindsight pass and prune, regardless of activity.
  precondition(signals) {
    const substantive = signals.commits?.substantiveChange === true;
    const logs = signals.conversationLogs ?? {};
    const canPrune = logs.present === true && typeof logs.retentionDays === 'number';

    if (substantive) {
      return { run: true, reason: 'substantive merge — extract any freshly captured conversation logs (+ retention prune)' };
    }
    if (canPrune) {
      return { run: true, reason: `logs branch present, retention ${logs.retentionDays}d — run the age-based retention prune` };
    }
    return { run: false, reason: logs.present ? 'no substantive merge and retention unset — nothing to prune' : 'no fresh captures and no logs branch' };
  },
};

// grow_with_claudinite task: growth-dedup — the growth lifecycle's PRUNING stage
// (per-project-scheduling DESIGN §6). Prunes local-pack items the canon now
// covers, keeping items the canon states too generally; opens a PR against the
// default branch for the owner to approve. Worker: task.md.
//
// The old fleet's `relevantCanonChanged` becomes the `sharedMount` signal — a
// declared pack's vendored files moving is the local echo of "the canon this repo
// mounts changed" — and the weekly re-check crutch retires: a quiet repo with no
// local packs skips.
//
// Self-contained (imports nothing): the whole contract is this default export.

export default {
  id: 'growth-dedup',
  frequency: 'daily+1h',           // the 05:00 slot — prunes against the merged/mounted canon, after promote (DESIGN §2)
  precondition_signals: ['localPacks', 'sharedMount', 'commits'],
  agent_model: 'opus',                   // proving the canon genuinely covers a local item — and telling coverage from "stated too generally" — is a judgment call
  expected_outcome: 'open-pr',              // a wrongful prune deletes a real local lesson, so this keeps a HUMAN approval gate (never auto-merge)
  agent_instructions: 'task.md',

  // Gate: the repo must actually track local packs (no local packs → nothing to
  // prune, self-skip). Given local packs, run when the mounted canon this repo
  // CARES about moved — a declared pack's vendored files changed (`sharedMount`),
  // which can newly cover a local item — or the repo's own local packs changed in
  // the window (a fresh local item to re-check against the canon). A quiet repo
  // with local packs but no relevant movement skips.
  precondition(signals) {
    const local = signals.localPacks ?? {};
    // `present` is null when the scheduler couldn't determine it; treat only an
    // explicit false as "definitely no local packs to prune".
    if (local.present === false) {
      return { run: false, reason: 'no local packs — nothing to prune' };
    }
    const changedPacks = signals.sharedMount?.changedPacks ?? [];
    const canonMoved = changedPacks.length > 0;
    const localChanged = local.changedInWindow === true;

    if (canonMoved) {
      return { run: true, reason: `declared pack(s) changed in the mounted canon: ${changedPacks.join(', ')} — local items may now be covered`, context: [`Re-check local items against these newly-changed canon packs: ${changedPacks.join(', ')}.`] };
    }
    if (localChanged) {
      return { run: true, reason: 'local packs changed in the window — re-check the fresh items against the mounted canon' };
    }
    return { run: false, reason: 'local packs present but no relevant canon or local movement in the window' };
  },
};

// product-wiki task: wiki-growth — one research-and-refine pass over the repo's
// product wikis (per-project-scheduling DESIGN §6). Worker: task.md.
//
// WEEKLY, not daily and not commit-gated: research arrives on the world's clock,
// not the repo's, and a nightly high-model pass economically pressures
// fabrication (the Karpathy LLM-wiki cadence). The `commits` signal is declared
// only so the precondition can note recent product-relevant movement in context;
// the run itself is scheduled by frequency, not triggered by a commit. The old
// open-growth-PR preflight is subsumed by the scheduler's at-most-one-open-issue
// guard, so the precondition simply lets the weekly slot through.
//
// Self-contained (imports nothing): the whole contract is this default export.

export default {
  id: 'wiki-growth',
  frequency: 'weekly',             // fires at the weekly anchor (DESIGN §2) — the world's clock, not the repo's
  precondition_signals: ['commits'],
  agent_model: 'opus',                   // open-web research + curation is the heaviest judgment, and the PR review gate is the last catch for fabrication
  expected_outcome: 'open-pr',              // web-researched claims entering a knowledge base need the human review gate — never merged, never pushed to default
  agent_instructions: 'task.md',

  // The weekly slot IS the trigger — there is no cheaper gate to apply, because a
  // wiki grows on research availability, not repo activity. Always run when due;
  // the worker's own stop condition (no citable material → no branch, no PR) is
  // the real "nothing to do" outcome, and the scheduler's one-open-dispatch-issue
  // guard prevents stacking a second round on an unreviewed PR.
  precondition(signals) {
    const touched = signals.commits?.touchedPaths ?? [];
    const wikiMoved = touched.some((p) => p.startsWith('product-wiki/'));
    const context = wikiMoved
      ? ['The product-wiki tree moved in the window — spot-check any pages whose cited claims the change may have superseded.']
      : [];
    return { run: true, reason: 'weekly product-wiki growth pass', context };
  },
};

// tidy-repo task: repo-tidy — the whole nightly tidy-up in one unit
// (per-project-scheduling DESIGN §6). One worker assesses this repo's branches
// and PRs read-only, acts on its issues, then reconciles the standing tracker
// from the verdicts. Worker: task.md. The old undeclared-canon carve-out dies —
// the canon repo declares tidy-repo like everyone else.
//
// Self-contained (imports nothing): the whole contract is this default export.

// Branches the tidy review must never assess. Beyond the default branch, the
// orphan `conversation-logs` branch is a grow_with_claudinite artifact (the
// captured-transcript stream, not project work) — it shares no history with main,
// so single-branch-status would flag it "orphaned" for a human on every widen. It
// is infrastructure the tidy sweep ignores altogether. Kept as a bare literal, not
// an import: the pack-independence barrier forbids tidy-repo from reaching into
// grow_with_claudinite, and the name is a fixed, well-known one. The stable
// maintenance branch is likewise never a tidy target — it is Claudinite's own
// standing delivery branch, not project work.
const IGNORED_BRANCHES = new Set(['conversation-logs', 'claudinite/maintenance']);

// A precondition has no repo handle, so it cannot look up the actual default
// branch name to drop it from the tidy candidate set — and the `branches` signal
// carries every open branch, the default included. Presuming the conventional
// default names here keeps a genuinely quiet repo (only its default branch open,
// no window activity) from firing tidy every night, which is the whole point of
// the gate. The worker (task.md) remains the authority that never assesses the
// repo's real default branch, so a repo whose default is unconventionally named
// is still safe — its default just also becomes a (cheap, read-only) tidy
// candidate here.
const PRESUMED_DEFAULT = new Set(['main', 'master']);

export default {
  id: 'repo-tidy',
  frequency: 'daily',              // the 04:00 slot (DESIGN §2)
  precondition_signals: ['prs', 'issues', 'branches', 'commits'],
  agent_model: 'sonnet',                 // the landed-status and implemented-in-main calls are judgment; the reconcile is mechanical
  expected_outcome: 'none',                 // assesses branches/PRs read-only and acts only on ISSUES — it never opens or merges a PR
  agent_instructions: 'task.md',

  // Run when the window surfaced genuine tidy work — a PR or issue actually
  // updated in the window — or on a SUBSTANTIVE default-branch move, which widens
  // the candidate set to ALL open branches/PRs/issues (a real commit can implement
  // an old issue or land an open PR without the object itself being touched). A
  // housekeeping-only main move (a nightly baseline commit, a bot bump) does not
  // widen — it lands nothing and implements nothing — so a quiet-but-maintained
  // repo isn't re-tidied every night.
  precondition(signals) {
    const substantive = signals.commits?.substantiveChange === true;

    // The branches collector surfaces names only, not the default-branch name, and
    // a precondition has no repo handle — so it cannot drop the default branch by
    // name here. It excludes the known infra branches (the ignore set above); the
    // worker (task.md) is the authority that never assesses the repo's own default
    // branch. The candidate set is the same whether or not the window was
    // substantive — an untouched branch is a cheap single-branch-status read that
    // collapses into the safe-to-delete line — so branches never gate on
    // substantiveChange, only PR/issue widening does.
    const branches = (signals.branches?.names ?? [])
      .filter((b) => !IGNORED_BRANCHES.has(b) && !PRESUMED_DEFAULT.has(b));

    // PRs/issues: widen to ALL open on a substantive move (a real commit can land
    // an open PR or implement an old issue without the object being touched);
    // otherwise only what the window actually touched.
    const openPrs = (signals.prs?.open ?? []).map((p) => p.number);
    const openIssues = (signals.issues?.open ?? []).map((i) => i.number);
    const touchedPrs = signals.prs?.touched ?? [];
    const touchedIssues = signals.issues?.touched ?? [];
    const prs = substantive ? openPrs : touchedPrs;
    const issues = substantive ? openIssues : touchedIssues;

    const active = substantive || touchedPrs.length || touchedIssues.length || branches.length;
    if (!active) return { run: false, reason: 'no touched PRs/issues, no non-default branches, no substantive move' };

    const reason = substantive
      ? 'project changed substantively — re-check landed status across all open objects'
      : 'repo activity in the window (touched PRs/issues or open branches)';
    const context = [];
    if (branches.length) context.push(`Branches to assess (read-only, recommend deletions only): ${branches.join(', ')}.`);
    if (prs.length) context.push(`PRs to assess (read-only): ${prs.map((n) => `#${n}`).join(', ')}.`);
    if (issues.length) context.push(`Issues to triage (the acting part): ${issues.map((n) => `#${n}`).join(', ')}.`);
    return { run: true, reason, context };
  },
};

