  const due = computeDueTaskSlots(tasks, D, '2026-07-22T06:00:00Z', '2026-07-21T06:00:00Z');
  assert.deepEqual(due.map((d) => d.task.id), ['a']);
  assert.equal(due[0].slotId, 'd2026-07-22');
});

