1	import { readdirSync, readFileSync, existsSync } from 'node:fs';
2	import { join, dirname } from 'node:path';
3	import { fileURLToPath } from 'node:url';
4	import { loadPacks, resolveDeclaredPacks, packEntryId, SHARED_SUBDIR } from '../engine/pack_loader/pack-registry.mjs';
5	import { relativeImports, resolveRelative, ENGINE_DIR_ROOTS } from '../engine/checks/helpers/module-imports.mjs';
6	
7	// The vendor-set computation for the vendored mount (DESIGN.md): given a repo's
8	// pack declaration, the minimal corpus file set that repo persists under
9	// SHARED_SUBDIR — canon-relative paths, mirroring exactly what a future
10	// submodule mounted at that same root would place there. Always computed
11	// against the canon tree THIS module ships in — the nightly runs it from the
12	// home checkout, an on-demand refresh from the tree it just fetched — so the
13	// set and the content can never come from different snapshots.
14	const canonRoot = dirname(dirname(fileURLToPath(import.meta.url))); // <canon>/vendoring/ — canon-internal, never vendored (#385)
15	
16	// Re-exported for the writers (the nightly update pass, an on-demand refresh):
17	// the consumer-side root the set materializes under.
18	export { SHARED_SUBDIR };
19	
20	// The engine is discovered structurally, never listed file-by-file: the engine
21	// root vendors wholesale (a new engine file ships with no edit here). The list
22	// lives in the engine lib (engine/checks/helpers/module-imports.mjs) — the same
23	// surface the pack-independence barrier confines pack imports to, so "what a
24	// pack may import" and "what every consumer carries" can never drift apart —
25	// re-exported here as the vendor-set contract (DESIGN.md). engine/ carries no
26	// tests (they live in engine-tests/, mirroring its structure — #385), so the
27	// engine walk is a plain copy minus *.md — engine docs are canon-maintainer
28	// reference, read upstream when needed, while a pack's .md files are the
29	// payload and ride its directory below (pack tests are still filtered here).
30	export { ENGINE_DIR_ROOTS };
31	
32	const isTest = (name) => name.endsWith('.test.mjs');
33	
34	function walk(relDir, files, errors, { engine = false } = {}) {
35	  let entries;
36	  try {
37	    entries = readdirSync(join(canonRoot, relDir), { withFileTypes: true });
38	  } catch (e) {
39	    errors.push({
40	      what: `${relDir} is not a readable directory in the canon tree: ${e.message}`,
41	      fix: `restore ${relDir}, or fix what names it (an engine root, a pack.mjs skills list)`,
42	    });
43	    return;
44	  }
45	  for (const entry of entries.sort((a, b) => a.name.localeCompare(b.name))) {
46	    if (entry.isDirectory()) {
47	      if (engine && entry.name === 'test') continue;
48	      walk(`${relDir}/${entry.name}`, files, errors, { engine });
49	    } else if (!isTest(entry.name) && !(engine && entry.name.endsWith('.md'))) {
50	      files.add(`${relDir}/${entry.name}`);
51	    }
52	  }
53	}
54	
55	// declaredEntries: the raw `packs` array from .claudinite-checks.json (id
56	// strings and/or entry objects). Returns { files, errors }:
57	// sorted canon-relative paths, and { what, fix } diagnostics. Ids naming no
58	// canon pack (a consumer's local packs, or a typo the runner's settings
59	// validation already flags) are skipped without error; per-user preferences
60	// are deliberately absent — they are never vendored (DESIGN.md). A pack's
61	// bundled skills (<pack>/skills/) ride its directory walk — there is no
62	// separate skills collection to union (#385).
63	export async function computeVendorSet(declaredEntries) {
64	  const files = new Set();
65	  const errors = [];
66	
67	  for (const root of ENGINE_DIR_ROOTS) walk(root, files, errors, { engine: true });
68	
69	  const packs = await loadPacks();
70	  const byId = new Map(packs.map((p) => [p.id, p]));
71	  const ids = [];
72	  for (const entry of resolveDeclaredPacks(declaredEntries ?? [], packs)) {
73	    const id = packEntryId(entry);
74	    if (id !== undefined && byId.has(id) && !ids.includes(id)) ids.push(id);
75	  }
76	  for (const id of ids) walk(`packs/${id}`, files, errors);
77	
78	  // Coherence guard: the set must be import-closed — every relative import in
79	  // every .mjs it carries resolves to a file it also carries. Structural
80	  // discovery plus the requires closure make that true by construction while
81	  // the corpus honors pack-independence (a pack imports only its own files and
82	  // the engine surface, both always in the set); a violation is canon-side
83	  // breakage, reported here so convergence aborts BEFORE any write (the
84	  // transactional contract) instead of the flipped member crashing on a
85	  // missing module — the failure the gated flip's pilot abort surfaced.
86	  const inSet = new Set(files);
87	  for (const file of inSet) {
88	    if (!file.endsWith('.mjs')) continue;
89	    let src;
90	    try { src = readFileSync(join(canonRoot, file), 'utf8'); } catch { continue; }
91	    for (const { spec } of relativeImports(src)) {
92	      const resolved = resolveRelative(file, spec, (p) => existsSync(join(canonRoot, p)));
93	      if (!resolved) {
94	        errors.push({
95	          what: `${file} imports "${spec}", which resolves to no file in the canon tree`,
96	          fix: 'fix the import specifier, or restore the file it names',
97	        });
98	      } else if (!inSet.has(resolved)) {
99	        errors.push({
